public void process()
{
    ccBatchWorkLoad     stagingTable;
    stagingTable.readPast(true);

    do
    {

        try
        {
            ttsBegin;

            select pessimisticlock firstOnly stagingTable
                where stagingTable.ccBatchProcStatus == ccBatchProcStatus::InProcessing;

            if (stagingTable)
            {
                ProcessStagingTable::processStagingTableRecord(stagingTable);
                stagingTable.ccBatchProcStatus = ccBatchProcStatus::Processed;
                stagingTable.update();
            }
            ttscommit;
        }
        catch
        {
            //revert data
            ttsabort;
            ttsbegin;
            ccBatchWorkLoad recordToUpdate;
            select forupdate firstonly recordToUpdate where recordToUpdate.RecId == stagingTable.RecId;
            recordToUpdate.ccBatchProcStatus = ccBatchProcStatus::Error;
            recordToUpdate.update();
            ttscommit;
            info('in the catch of MultiThreadingGetWorkItemService.process()');
            //log errors
        }

    }
    while (stagingTable);
}
